class TicTacToe {
    int[] rows, cols;
    int diagonal, anti_diagonal, n;

    public TicTacToe(int n) {
        this.n = n;
        rows = new int[n];
        cols = new int[n];
        diagonal = 0;
        anti_diagonal = 0;
    }

    public int move(int row, int col, int player) {
        int toAdd = (player == 1) ? 1 : -1;

        rows[row] += toAdd;
        cols[col] += toAdd;

        if (row == col) diagonal += toAdd;
        if (row + col == n - 1) anti_diagonal += toAdd;

        if (Math.abs(rows[row]) == n || 
            Math.abs(cols[col]) == n || 
            Math.abs(diagonal) == n || 
            Math.abs(anti_diagonal) == n)
            return player;

        return 0;
    }
}
```


